function updateZZBandFill(angleDeg) {
  if (!guideLines || !zzDirection || !stage) {
    return;
  }

  const stageRect = stage.getBoundingClientRect();
  const stageHeight = stage.offsetHeight;
  const pFrom = dateToProgress(parseMonth("1945-01"));
  const pTo = dateToProgress(parseMonth("1960-01"));
  const yFrom = stageRect.top + pFrom * stageHeight;
  const yTo = stageRect.top + pTo * stageHeight;

  const zzDir = zzDirection.unit;
  const zzLineFrom = lineFromPointAndDir(timelineCenterPointAtViewportY(yFrom, angleDeg), zzDir);
  const zzLineTo = lineFromPointAndDir(timelineCenterPointAtViewportY(yTo, angleDeg), zzDir);

  const side = 1;
  const lineNumber = 1;
  const params = getGuideTransformParams();
  const blackLine = lineFromPoints(
    guideLocalPointToViewport(0, guideLocalY(side, lineNumber, 0), angleDeg, params),
    guideLocalPointToViewport(1000, guideLocalY(side, lineNumber, 1000), angleDeg, params)
  );
  const pinkP0 = projectedPinkLocalPoint(side, lineNumber, 0, angleDeg, params);
  const pinkP1 = projectedPinkLocalPoint(side, lineNumber, 1000, angleDeg, params);
  const pinkLine = lineFromPoints(
    guideLocalPointToViewport(pinkP0.x, pinkP0.y, angleDeg, params),
    guideLocalPointToViewport(pinkP1.x, pinkP1.y, angleDeg, params)
  );

  const blackFrom = intersectLines(blackLine, zzLineFrom);
  const pinkFrom = intersectLines(pinkLine, zzLineFrom);
  const pinkTo = intersectLines(pinkLine, zzLineTo);
  const blackTo = intersectLines(blackLine, zzLineTo);

  if (!blackFrom || !pinkFrom || !pinkTo || !blackTo) {
    const existing = guideLines.querySelector("#zz-band-fill");
    if (existing) {
      existing.remove();
    }
    return;
  }

  const p1 = viewportPointToGuideLocal(blackFrom.x, blackFrom.y, angleDeg, params);
  const p2 = viewportPointToGuideLocal(pinkFrom.x, pinkFrom.y, angleDeg, params);
  const p3 = viewportPointToGuideLocal(pinkTo.x, pinkTo.y, angleDeg, params);
  const p4 = viewportPointToGuideLocal(blackTo.x, blackTo.y, angleDeg, params);
  const points = [`${p1.x},${p1.y}`, `${p2.x},${p2.y}`, `${p3.x},${p3.y}`, `${p4.x},${p4.y}`].join(" ");

  let band = guideLines.querySelector("#zz-band-fill");
  if (!band) {
    band = document.createElementNS("http://www.w3.org/2000/svg", "polygon");
    band.setAttribute("id", "zz-band-fill");
    band.setAttribute("fill", "rgba(214, 58, 136, 0.22)");
    band.setAttribute("stroke", "rgba(214, 58, 136, 0.45)");
    band.setAttribute("stroke-width", "1");
    band.setAttribute("vector-effect", "non-scaling-stroke");
    guideLines.append(band);
  }
  band.setAttribute("points", points);
}

